// 1. as Sintaksisi ilə Type Assertion
let value: any = "Hello";
let strLength: number = (value as string).length;
console.log(strLength); // Çıxış: 5

// 2. Angle-Bracket Sintaksisi
let value2: any = "World";
let strLength2: number = (<string>value2).length;
console.log(strLength2); // Çıxış: 5

// 3. Union Tipləri ilə Type Assertion
function processValue(value: string | number) {
  let result: string = (value as string).toUpperCase(); // Ehtiyatlı olun, number olarsa səhv ola bilər
  console.log(result);
}
processValue("hello"); // Çıxış: HELLO
// processValue(42); // Runtime səhvi: number.toUpperCase mövcud deyil

// 4. unknown ilə Type Assertion
let data: unknown = "Test";
let str: string = data as string; // unknown-dan string-ə çevrilir
console.log(str.toUpperCase()); // Çıxış: TEST

// 5. Type Assertion ilə Obyekt
interface User {
  name: string;
  age: number;
}
let rawData: any = { name: "Alice", age: 30 };
let user: User = rawData as User;
console.log(user.name); // Çıxış: Alice

// 6. Type Assertion və Type Guard ilə birlikdə
function isString(value: any): value is string {
  return typeof value === "string";
}
function safeProcess(value: any) {
  if (isString(value)) {
    console.log(value.toUpperCase());
  } else {
    let num: number = value as number; // Type assertion ilə number təyin edilir
    console.log(num.toFixed(2));
  }
}
safeProcess("Hello"); // Çıxış: HELLO
safeProcess(42.123); // Çıxış: 42.12

// Sadə mağaza sistemi
interface Product {
  id: string;
  name: string;
  price: number;
}

// API-dən gələn məlumatla Type Assertion
let rawProduct: any = { id: "P001", name: "Laptop", price: 999 };
let product: Product = rawProduct as Product;
console.log(product.name); // Çıxış: Laptop

// Type Guard ilə təhlükəsiz Type Assertion
function isProduct(data: any): data is Product {
  return (
    data &&
    typeof data.id === "string" &&
    typeof data.name === "string" &&
    typeof data.price === "number"
  );
}
function processProduct(data: any) {
  if (isProduct(data)) {
    console.log(`Product: ${data.name}, Price: ${data.price}`);
  } else {
    console.log("Invalid product data");
  }
}
processProduct(rawProduct); // Çıxış: Product: Laptop, Price: 999
processProduct({ id: "P002" }); // Çıxış: Invalid product data

